<script setup lang="ts">
import {computed,onMounted,reactive,ref} from 'vue';import {api,type Envelope} from '@/api';import {ElMessage,ElMessageBox} from 'element-plus';import {useAuthStore} from '@/stores/auth';
const auth=useAuthStore(),superAdmin=computed(()=>auth.can('user:admin:manage')),rows=ref<any[]>([]),stations=ref<any[]>([]),dialog=ref(false),form=reactive<any>({username:'',displayName:'',role:'MENTOR',stationIds:[]});async function load(){rows.value=(await api.get<any,Envelope<any[]>>('/users')).data;if(superAdmin.value)stations.value=(await api.get<any,Envelope<any[]>>('/stations')).data}async function create(){const r=await api.post<any,Envelope<any>>('/users',form);dialog.value=false;await ElMessageBox.alert(`临时密码：${r.data.temporaryPassword}`,'账号已创建');load()}async function reset(row:any){const r=await api.post<any,Envelope<any>>(`/users/${row.id}/reset-password`);await ElMessageBox.alert(`临时密码：${r.data.temporaryPassword}`,'密码已重置')}async function toggle(row:any){await api.put(`/users/${row.id}/enabled`,{enabled:!row.enabled});ElMessage.success('状态已更新');load()}async function changeRole(row:any,role:string){await api.put(`/users/${row.id}/role`,{role});ElMessage.success('角色已更新，旧令牌已失效');load()}onMounted(load);
</script>
<template><div class="page"><div class="page-head"><h2>账号管理</h2><el-button v-if="superAdmin" type="primary" @click="dialog=true">创建管理账号</el-button></div><el-table :data="rows"><el-table-column prop="username" label="用户名"/><el-table-column prop="display_name" label="姓名"/><el-table-column label="角色"><template #default="s"><el-select v-if="superAdmin&&s.row.id!==auth.user?.id&&s.row.role!=='STATION_MANAGER'" :model-value="s.row.role" @change="(v:any)=>changeRole(s.row,v)"><el-option v-for="r in ['MENTOR','TRAINING_ADMIN','ADMIN','SUPER_ADMIN']" :key="r" :value="r" :label="r"/></el-select><span v-else>{{s.row.role}}</span></template></el-table-column><el-table-column prop="enabled" label="启用"/><el-table-column label="操作"><template #default="s"><el-button v-if="s.row.role==='EMPLOYEE'||superAdmin" link @click="reset(s.row)">重置密码</el-button><el-button v-if="(s.row.role==='EMPLOYEE'||superAdmin)&&s.row.id!==auth.user?.id" link @click="toggle(s.row)">{{s.row.enabled?'停用':'启用'}}</el-button></template></el-table-column></el-table><el-dialog v-model="dialog" title="创建账号"><el-input v-model="form.username" placeholder="用户名"/><el-input v-model="form.displayName" placeholder="姓名"/><el-select v-model="form.role"><el-option label="导师" value="MENTOR"/><el-option label="服务站长" value="STATION_MANAGER"/><el-option label="培训管理员" value="TRAINING_ADMIN"/><el-option label="系统管理员" value="ADMIN"/></el-select><el-select v-if="form.role==='STATION_MANAGER'" v-model="form.stationIds" multiple placeholder="所属服务站"><el-option v-for="x in stations" :key="x.id" :label="x.name" :value="x.id"/></el-select><template #footer><el-button type="primary" @click="create">创建</el-button></template></el-dialog></div></template>
